module RefModule (
    input wire [1:0] x,   // 2-bit input
    output wire y         // 1-bit output
);
    parameter W0 = 2'b01;  // Weight for input x0
    parameter W1 = 2'b01;  // Weight for input x1
    parameter THRESHOLD = 1; // Threshold for activation

    wire [1:0] weighted_sum;

      wire _n01 = (x[0] * W0)[0] ^ (x[1] * W1)[0];
  wire _c01 = (x[0] * W0)[0] & (x[1] * W1)[0];
  wire _n02 = (x[0] * W0)[1] ^ (x[1] * W1)[1] ^ _c01;
  wire _c02 = ((x[0] * W0)[1] & (x[1] * W1)[1]) | ((x[0] * W0)[1] & _c01) | ((x[1] * W1)[1] & _c01);
  wire _n03 = (x[0] * W0)[2] ^ (x[1] * W1)[2] ^ _c02;
  wire _c03 = ((x[0] * W0)[2] & (x[1] * W1)[2]) | ((x[0] * W0)[2] & _c02) | ((x[1] * W1)[2] & _c02);
  wire _n04 = (x[0] * W0)[3] ^ (x[1] * W1)[3] ^ _c03;
  wire _c04 = ((x[0] * W0)[3] & (x[1] * W1)[3]) | ((x[0] * W0)[3] & _c03) | ((x[1] * W1)[3] & _c03);
  assign weighted_sum = {_n01, _n02, _n03, _n04};
    assign y = (weighted_sum > THRESHOLD) ? 1'b1 : 1'b0;

endmodule
